/**
 * netlify/functions/parse-product-ai.js
 *
 * Rule-based product parser for Al Zaydan International Admin.
 * Parses structured product descriptions (generated by any external AI)
 * into clean JSON to auto-populate the Admin Product Form.
 *
 * Structured Template Format:
 *
 * ### Product Name – Model Number (optional)
 *
 * [Description paragraphs here]
 *
 * ---
 * ### Product Sourcing Properties
 * - **Brand:** Value
 * - **Category:** Value
 * - **Price:** Value (or "Hidden: RFQ / Price on Request" or "120 AED" or "100–150 AED")
 * - **MOQ:** Value
 * - **Lead Time:** Value
 * - **Shipping Region:** Value
 *
 * ### Marketing & Trust Badges
 * - **Product Badge:** Bulk Deal | Bestseller | Top Rated | New | Hot | (blank)
 * - **Trust Badges:** Verified Supplier, GCC Supply
 * - **Status:** In Stock | Out of Stock
 * - **Sourcing Highlights:** Featured on Homepage | Top Selling | (blank)
 *
 * ### Technical Specifications
 * - **Spec Key:** Spec Value
 * - **Another Key:** Another Value
 *
 * ### Media Assets
 * - **Primary Image:** https://...
 * - **Additional Images:** https://..., https://...
 *
 * ### SEO & Open Graph Directives
 * - **Focus Keyword:** keyword phrase here
 * - **SEO Title:** Title Here | Al Zaydan
 * - **Meta Description:** Description here.
 */

export const handler = async (event) => {
  // CORS preflight
  if (event.httpMethod === 'OPTIONS') {
    return {
      statusCode: 200,
      headers: {
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Headers': 'Content-Type',
        'Access-Control-Allow-Methods': 'POST, OPTIONS'
      },
      body: ''
    };
  }

  if (event.httpMethod !== 'POST') {
    return {
      statusCode: 405,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ error: 'Method Not Allowed. Use POST.' })
    };
  }

  try {
    const payload = JSON.parse(event.body || '{}');
    const { rawText } = payload;

    if (!rawText || !rawText.trim()) {
      return {
        statusCode: 400,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ error: 'Missing rawText parameter in request body.' })
      };
    }

    const parsedData = parseStructuredProduct(rawText.trim());

    return {
      statusCode: 200,
      headers: {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': '*'
      },
      body: JSON.stringify(parsedData)
    };

  } catch (err) {
    console.error('[parse-product] Error:', err);
    return {
      statusCode: 500,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        error: 'Failed to parse product details.',
        details: err.message
      })
    };
  }
};

// ─── Rule-Based Parser ────────────────────────────────────────────────────────

function parseStructuredProduct(rawText) {
  const result = {
    name: '',
    brand: '',
    category: '',
    priceType: 'hidden',
    price: '',
    priceMin: '',
    priceMax: '',
    moq: '',
    leadTime: '',
    shippingRegion: 'UAE / GCC',
    description: '',
    specifications: [],
    image: '',
    images: [],
    slug: '',
    seoTitle: '',
    metaDescription: '',
    focusKeyword: '',
    inStock: true,
    topSelling: false,
    featured: false,
    badge: '',
    trustBadges: [],
    ogTitle: '',
    ogDescription: '',
    twitterTitle: '',
    twitterDescription: ''
  };

  // ── 1. Split into named sections by "### Heading" ────────────────────────
  const sectionStarts = [];
  const sectionHeadingRe = /^###\s+(.+)$/gm;
  let m;
  while ((m = sectionHeadingRe.exec(rawText)) !== null) {
    sectionStarts.push({ title: m[1].trim(), index: m.index });
  }

  // Build a map: section title (lower) → section text content
  const sections = {};
  for (let i = 0; i < sectionStarts.length; i++) {
    const start = sectionStarts[i].index;
    const end = sectionStarts[i + 1] ? sectionStarts[i + 1].index : rawText.length;
    const key = sectionStarts[i].title.toLowerCase();
    sections[key] = rawText.slice(start, end);
  }

  // ── 2. Product Name — first ### heading ──────────────────────────────────
  if (sectionStarts.length > 0) {
    // Remove trailing "– Model XXXXX" from title if present
    result.name = sectionStarts[0].title
      .replace(/\s*[-–—]\s*Model\s+\S+\s*$/i, '')
      .trim();
  } else {
    // Fallback: use first non-empty line
    const firstLine = rawText.split('\n').find(l => l.trim());
    result.name = firstLine ? firstLine.replace(/^#+\s*/, '').trim() : '';
  }

  // ── 3. Description — text between first heading and second section ────────
  if (sectionStarts.length > 0) {
    const firstSectionEnd = sectionStarts.length > 1
      ? sectionStarts[1].index
      : rawText.length;
    const firstBlock = rawText.slice(sectionStarts[0].index, firstSectionEnd);
    // Remove the heading line itself and horizontal rules
    const descText = firstBlock
      .split('\n')
      .slice(1) // skip the ### heading
      .filter(l => l.trim() !== '---')
      .join('\n')
      .trim();
    result.description = descText;
  }

  // ── Helper: extract "- **Field:** Value" from a section block ────────────
  function field(sectionText, ...fieldNames) {
    for (const fieldName of fieldNames) {
      const re = new RegExp(
        `-\\s*\\*{0,2}${escapeRe(fieldName)}\\*{0,2}\\s*:?\\s*(.+)`,
        'i'
      );
      const match = sectionText.match(re);
      if (match) {
        // Strip surrounding quotes, asterisks, backticks
        return match[1].trim().replace(/^[*"`'\s]+|[*"`'\s]+$/g, '').trim();
      }
    }
    return '';
  }

  function escapeRe(s) {
    return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  // ── 4. Product Sourcing Properties ───────────────────────────────────────
  const sourcingKey = findSection(sections, ['sourcing', 'propert']);
  if (sourcingKey) {
    const s = sections[sourcingKey];
    result.brand = field(s, 'Brand');
    result.category = field(s, 'Category');
    result.moq = field(s, 'MOQ', 'Minimum Order Quantity');
    result.leadTime = field(s, 'Lead Time', 'Lead time');
    result.shippingRegion = field(s, 'Shipping Region', 'Ships to') || 'UAE / GCC';

    const priceRaw = field(s, 'Price');
    if (!priceRaw || /hidden|rfq|request|inqui|contact/i.test(priceRaw)) {
      result.priceType = 'hidden';
      result.price = '';
      result.priceMin = '';
      result.priceMax = '';
    } else {
      // Range: "100–200" or "100 - 200"
      const rangeMatch = priceRaw.match(/(\d[\d,.]*)\s*[-–—]\s*(\d[\d,.]*)/);
      if (rangeMatch) {
        result.priceType = 'range';
        result.priceMin = rangeMatch[1].replace(/,/g, '');
        result.priceMax = rangeMatch[2].replace(/,/g, '');
      } else {
        // Fixed price — extract digits
        const fixedMatch = priceRaw.match(/([\d,.]+)/);
        if (fixedMatch) {
          result.priceType = 'fixed';
          result.price = fixedMatch[1].replace(/,/g, '');
        } else {
          result.priceType = 'hidden';
        }
      }
    }
  }

  // ── 5. Marketing & Trust Badges ──────────────────────────────────────────
  const marketingKey = findSection(sections, ['marketing', 'trust', 'badge']);
  if (marketingKey) {
    const s = sections[marketingKey];

    const badgeRaw = field(s, 'Product Badge', 'Badge');
    const validBadges = ['Bestseller', 'Top Rated', 'New', 'Hot', 'Bulk Deal'];
    result.badge = validBadges.find(b => b.toLowerCase() === badgeRaw.toLowerCase()) || '';

    const trustRaw = field(s, 'Trust Badges', 'Trust Badge');
    if (trustRaw) {
      const validTrust = ['Verified Supplier', 'Export Ready', 'ISO Certified', 'GCC Supply', 'Fast Dispatch'];
      result.trustBadges = trustRaw
        .split(',')
        .map(t => t.trim())
        .filter(t => validTrust.some(v => v.toLowerCase() === t.toLowerCase()))
        .map(t => validTrust.find(v => v.toLowerCase() === t.toLowerCase()));
    }

    const status = field(s, 'Status');
    result.inStock = !status || /in.?stock|available/i.test(status);

    const highlights = field(s, 'Sourcing Highlights', 'Highlights');
    result.featured = /featured/i.test(highlights);
    result.topSelling = /top.?sell|best.?sell|trending/i.test(highlights);
  }

  // ── 6. Technical Specifications ──────────────────────────────────────────
  const specsKey = findSection(sections, ['spec', 'technical']);
  if (specsKey) {
    const s = sections[specsKey];
    // Match lines: "- **Key:** Value" or "- **Key**: Value"
    const specLineRe = /-\s*\*{0,2}([^*:\n]+?)\*{0,2}\s*:\s*(.+)/gm;
    let sm;
    while ((sm = specLineRe.exec(s)) !== null) {
      const key = sm[1].replace(/\*+/g, '').trim();
      const value = sm[2].replace(/^[*"`'\s]+|[*"`'\s]+$/g, '').trim();
      if (key && value && key.length < 80 && value.length < 300) {
        result.specifications.push({ key, value });
      }
    }
  }

  // ── 7. Media Assets ───────────────────────────────────────────────────────
  const mediaKey = findSection(sections, ['media', 'asset', 'image']);
  if (mediaKey) {
    const s = sections[mediaKey];
    const primaryRaw = field(s, 'Primary Image', 'Main Image', 'Image');
    if (primaryRaw && /^https?:\/\//i.test(primaryRaw)) {
      result.image = primaryRaw;
    }

    const additionalRaw = field(s, 'Additional Images', 'Gallery Images', 'Images');
    if (additionalRaw) {
      const urls = additionalRaw.match(/https?:\/\/[^\s"',]+/g) || [];
      result.images = urls;
    }
  }

  // Also scan full text for any image URLs not in media section
  if (!result.image) {
    const imgMatch = rawText.match(/https?:\/\/\S+\.(?:png|jpg|jpeg|webp)/i);
    if (imgMatch) result.image = imgMatch[0];
  }

  // ── 8. SEO & Open Graph ───────────────────────────────────────────────────
  const seoKey = findSection(sections, ['seo', 'open graph', 'og directive']);
  if (seoKey) {
    const s = sections[seoKey];
    result.focusKeyword = field(s, 'Focus Keyword', 'Target Keyword', 'Keyword');
    result.seoTitle = field(s, 'SEO Title', 'Title Tag', 'Meta Title');
    result.metaDescription = field(s, 'Meta Description', 'Meta Desc');
    result.ogTitle = field(s, 'OG Title', 'Open Graph Title', 'og:title') || result.seoTitle;
    result.ogDescription = field(s, 'OG Description', 'Open Graph Description', 'og:description') || result.metaDescription;
    result.twitterTitle = field(s, 'Twitter Title', 'twitter:title') || result.seoTitle;
    result.twitterDescription = field(s, 'Twitter Description', 'twitter:description') || result.metaDescription;
  }

  // Fallback OG/Twitter from SEO fields
  if (!result.ogTitle) result.ogTitle = result.seoTitle;
  if (!result.ogDescription) result.ogDescription = result.metaDescription;
  if (!result.twitterTitle) result.twitterTitle = result.seoTitle;
  if (!result.twitterDescription) result.twitterDescription = result.metaDescription;

  // ── 9. Generate slug from name ────────────────────────────────────────────
  if (result.name) {
    result.slug = result.name
      .toLowerCase()
      .replace(/[^\w\s-]/g, '')
      .replace(/[\s_]+/g, '-')
      .replace(/^-+|-+$/g, '');
  }

  return result;
}

// ── Find the first section key matching any of the given partial strings ──────
function findSection(sections, partials) {
  const keys = Object.keys(sections);
  for (const partial of partials) {
    const found = keys.find(k => k.includes(partial));
    if (found) return found;
  }
  return null;
}
